mapper.select:
select p.*, e.emp_name,
       (select count(*) from project_member pm where pm.project_pro_id = p.pro_id) as memberCnt
from project p
join employee e on p.emp_id = e.emp_id
join company c on p.com_id = c.com_id


	and p.pro_name like concat('%', #{keyword}, '%')


	and p.pro_status = #{proStatus}


	and p.start_date  >= #{startDate}


	and p.end_date <= #{endDate}


order by p.pro_id desc
limit #{pstartno}, #{onepagelist}

select p.*, e.emp_name as empName, 
       (select count(*) from project_member pm where pm.project_pro_id = p.pro_id) as memberCnt
from project p join employee e on p.emp_id = e.emp_id
where p.start_date <= #{endDate}
  and p.end_date >= #{startDate}
order by p.pro_id desc
